import{_ as e}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as a,o as l,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"프로젝트 설정 (Project Settings)","description":"","frontmatter":{},"headers":[],"relativePath":"ko/configuration/project-settings.md","filePath":"ko/configuration/project-settings.md"}'),r={name:"ko/configuration/project-settings.md"};function n(s,t,i,c,g,h){return l(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="프로젝트-설정-project-settings" tabindex="-1"><i class="ph-fill ph-gear-six"></i> 프로젝트 설정 (Project Settings) <a class="header-anchor" href="#프로젝트-설정-project-settings" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; 프로젝트 설정 (Project Settings)&quot;">​</a></h1><p>모든 글로벌 WebAP 설정은 단일 위치에 집중되어 있습니다: <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+e+'" alt=""></p><h2 id="일반-설정-general-settings" tabindex="-1">일반 설정 (General Settings) <a class="header-anchor" href="#일반-설정-general-settings" aria-label="Permalink to &quot;일반 설정 (General Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">매개변수</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">기본 성능 목표치입니다. • 현재 FPS가 이 값 아래로 떨어지면(성능 여유를 고려하여) 플러그인이 그래픽 품질을 줄이기 시작합니다. • FPS가 일관되게 이 값 위에 유지되면 플러그인은 품질 개선을 시도합니다. <em>권장 사항:</em> 합리적인 값을 설정하세요. WebGL의 경우 사실상 표준은 <code>60</code>이지만 무거운 3D 프로젝트의 경우 <code>30</code>을 활용할 수 있습니다.</td></tr></tbody></table><h2 id="인덱서-설정-indexer-settings" tabindex="-1">인덱서 설정 (Indexer Settings) <a class="header-anchor" href="#인덱서-설정-indexer-settings" aria-label="Permalink to &quot;인덱서 설정 (Indexer Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">매개변수</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">품질을 <em>낮춘</em> 후 시스템이 FPS를 재평가하기 전에 기다리는 시간(초)입니다. <em>권장 사항:</em> 짧아야 합니다(<code>1.0</code> - <code>2.0</code> 초). 시스템은 지연에 민첩하게 반응하고 FPS가 안정화될 때까지 &quot;짐을 버려야&quot; 합니다.</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;">품질을 <em>높인</em> 후 대기 시간입니다. <em>권장 사항:</em> 길어야 합니다(<code>5.0</code> - <code>10.0</code> 초). 시스템에 다시 부담을 주기 전에 이전 그래픽 향상이 프레임 안정성을 망치지 않았는지 확인해야 합니다.</td></tr></tbody></table><h2 id="안티-요요-페널티-시스템-anti-yo-yo-penalty-system" tabindex="-1">안티 요요 페널티 시스템 (Anti Yo-Yo Penalty System) <a class="header-anchor" href="#안티-요요-페널티-시스템-anti-yo-yo-penalty-system" aria-label="Permalink to &quot;안티 요요 페널티 시스템 (Anti Yo-Yo Penalty System)&quot;">​</a></h2><p>품질이 두 수준 사이에서 끝없이 번갈아 나타나는 &quot;요요 현상&quot;을 방지합니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">매개변수</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">품질을 <em>높인</em> 후 시스템이 FPS를 면밀히 모니터링하는 시간입니다. 이 기간 동안 FPS 강하가 발생하면 시스템은 이를 요요 현상으로 분류합니다.</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">품질을 <em>높이려는</em> 시도가 단호하게 차단되는 페널티 기간(예: <code>60</code> 초)입니다.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">참고</p><p>페널티는 오직 품질 증가만 차단합니다. FPS가 다시 떨어지면 시스템은 여전히 응급으로 품질을 줄일 수 있습니다.</p></div><h2 id="스케일러-scalers" tabindex="-1">스케일러 (Scalers) <a class="header-anchor" href="#스케일러-scalers" aria-label="Permalink to &quot;스케일러 (Scalers)&quot;">​</a></h2><p>활성화된 각 Scaler는 일련의 기준 매개변수를 갖습니다. 이러한 매개변수는 시스템에 대한 &quot;비용&quot;을 지정합니다. 플러그인은 실시간으로 이 비용을 자동으로 계산합니다: 시각적 영향이 가장 적고 해당 대상(Target - CPU/GPU)과 일치하는 Scaler가 먼저 호출됩니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">매개변수</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">기본 품질과 최소 품질 사이의 이산적인 단계(레벨) 수입니다. 예를 들어 <code>Max Level = 4</code>는 이 Scaler에 4개의 품질 저하 단계가 있음을 의미합니다.</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">최소 스케일 값입니다(Scaler가 <code>Max Level</code>에 도달할 때 적용됨). 예를 들어 <code>0.5</code>는 원본의 50%로 품질이 저하됨을 나타냅니다.</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">최대 스케일 값입니다. 일반적으로 <code>1.0</code>(100% 품질)과 동일하며 Nível 0의 기본값입니다.</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">렌더링 시 시각적 영향도(<code>Low</code>, <code>Medium</code>, <code>High</code>). 플러그인은 시각적 영향이 <code>Low</code>인 Scaler에 대해 품질을 체계적으로 우선 감소(레벨 증가)시킵니다.</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">Scaler가 최적화하는 하위 시스템을 지정합니다(<code>CPU</code>, <code>GPU</code> 또는 둘 다). 시스템의 현재 병목 현상(Bottleneck)이 <code>CPU</code>인 경우 플러그인은 <code>GPU</code>에 초점을 맞춘 Scaler를 무시합니다.</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">특정 전용 Scaler(<code>WebResolutionScaler</code>, <code>WebCameraClipScaler</code>, <code>WebLayerCullingScaler</code>)는 설정을 전역적으로 실행하는 대신 씬의 특정 카메라에 적용합니다.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">카메라 태그(Camera Tags) 작업</p><p>이 Scaler들은 <code>Camera.main</code> 호출을 사용하지 않습니다. 대신 <code>Target Tags</code> 배열을 사용하여 활성 카메라를 스캔합니다.</p><p>기본적으로 <code>MainCamera</code> 태그가 여기에 지정되어 있습니다. <strong>게임이 맞춤형 카메라 태그(예: <code>PlayerCamera</code>)를 사용하는 경우 Scaler 설정에 이를 추가해야 합니다.</strong> 그렇지 않으면 해당 카메라에서 스케일이 트리거되지 않습니다.</p></div><h2 id="개발-설정-development-settings" tabindex="-1">개발 설정 (Development Settings) <a class="header-anchor" href="#개발-설정-development-settings" aria-label="Permalink to &quot;개발 설정 (Development Settings)&quot;">​</a></h2><p>이 섹션은 브라우저 또는 에디터에서 플러그인의 동작을 디버깅하는 전용입니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">매개변수</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">브라우저(또는 Unity) 콘솔에 플러그인 작업에 대한 자세한 추적을 로그로 남길 수 있습니다. 병목 현상 변화, Scaler 활성화, 안티 요요 페널티 시스템 작동에 대한 메시지를 출력합니다.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">최적화</p><p>로깅은 내부 <code>DebugWebAP</code> 래퍼를 사용합니다. 리소스를 보존하고 콘솔을 깨끗하게 유지하기 위해 프로덕션(출시) 빌드에서는 <code>Logging</code> 옵션을 비활성화하는 것이 강력히 권장됩니다.</p></div>',19)])])}const f=a(r,[["render",n]]);export{p as __pageData,f as default};
